#!/usr/bin/env node
/**
 * Creates a claude/* branch, commits the daily summary report, and opens a draft PR
 * using the GitHub REST API (no git CLI needed).
 */

const OWNER = "InnerScopeHearing";
const REPO = "otchealth-claude-tools";
const BRANCH = "claude/daily-summary-2026-06-30";
const BASE = "main";
const REPORT_PATH = "reports/daily-summary-2026-06-30.md";

// The report content
const REPORT_CONTENT = `# Daily Summary — 2026-06-30

**Repo:** \`otchealth-claude-tools\`
**Period:** last 24 h (since 2026-06-29 01:11 UTC)
**Commits:** 1

---

## Commit \`333c922\` — PR #243

**fix(token-keeper,ocr-sweep): real QBO multi-entity rotation + OCR OOM guard**
Merged 2026-06-30 01:10 UTC by \`otchealth-fleet-bot\`

### token-keeper (\`skills/token-keeper/\`)

New skill wired to the nightly Azure Container App Job for OAuth refresh-token rotation.

**What broke:** the QuickBooks provider was reading placeholder secret names
(\`quickbooks-client-id\`, \`quickbooks-refresh-token\`) that do not exist in Secret Manager.
Every nightly run silently no-op'd (\`MISSING_SECRETS\`), masked by \`|| true\` in the job
shell, so \`lastRefresh\` was always \`null\` and QBO tokens were never actually rotated.

**What was fixed:**
- Corrected secret names to \`qbo-client-id\` / \`qbo-client-secret\`.
- QBO has 4 separate rotating refresh tokens, one per entity:
  \`qbo-refresh-otchealth\`, \`qbo-refresh-innd\`, \`qbo-refresh-hearingassist\`, \`qbo-refresh-personal\`.
- Introduced \`refreshOneOAuth()\` / \`refreshOAuth()\` multi-tenant loop; Xero stays
  single-tenant (same code path, unchanged behaviour).
- \`status\` and \`create-slots\` commands now enumerate all per-entity secrets.
- Verified by dry-run: all 4 entities resolve correctly.

**Files added:** \`skills/token-keeper/keeper.mjs\` (297 lines), \`SKILL.md\`, \`run.sh\`

---

### ocr-sweep (\`skills/ocr-sweep/\`)

Azure Document Intelligence auto-OCR sweep for the legal and CFO document stores.

**What broke:** \`sweep.mjs\` buffered each blob fully in memory with \`CONC=6\` concurrent
workers. One oversized file OOM-killed the 1 Gi container; the \`docintel-ocr-sweep\`
job had been failing for 30+ hours before this fix and no new text sidecars were being
written.

**What was fixed:**
- Added \`MAX_MB\` guard (default 200 MB). Checks \`Content-Length\` BEFORE calling
  \`arrayBuffer()\`, so an oversized blob is skipped without ever loading it into memory.
- Oversize files are left unprocessed and reported in the final summary line.
- Job resource limits bumped to 4 Gi RAM / 2 CPU and \`CONC\` dropped to 2
  (applied via ARM template update, not in this file).

**File added:** \`skills/ocr-sweep/sweep.mjs\` (69 lines)

---

## Impact summary

| Area | Severity | Status |
|---|---|---|
| QBO token rotation (all 4 entities silently failing) | High: tokens expire without rotation | Fixed |
| OCR sweep OOM crash (30 h outage, no sidecars written) | High: CFO/legal text layer stalled | Fixed |

Both issues were surfaced by the 2026-06-30 functional E2E test run.
Toolkit test gate: green (19 targets).

---

*Generated by CTO agent, 2026-06-30*
`;

async function ghApi(token, path, method = "GET", body = undefined) {
  const res = await fetch(`https://api.github.com${path}`, {
    method,
    headers: {
      Authorization: `Bearer ${token}`,
      Accept: "application/vnd.github+json",
      "X-GitHub-Api-Version": "2022-11-28",
      "Content-Type": "application/json",
    },
    body: body ? JSON.stringify(body) : undefined,
  });
  const json = await res.json().catch(() => ({}));
  if (!res.ok) {
    throw new Error(`GitHub API ${method} ${path} -> ${res.status}: ${JSON.stringify(json)}`);
  }
  return json;
}

async function main() {
  // Get token — prefer GH_TOKEN then GITHUB_TOKEN
  const token = process.env.GH_TOKEN || process.env.GITHUB_TOKEN;
  if (!token) {
    // Try reading from gh config
    const { execSync } = await import("node:child_process");
    try {
      const t = execSync("gh auth token 2>/dev/null", { encoding: "utf8" }).trim();
      if (t) {
        process.env.GH_TOKEN = t;
        return main(); // retry with token set
      }
    } catch {}
    throw new Error("No GitHub token found (GH_TOKEN, GITHUB_TOKEN, or gh auth token)");
  }

  console.log("1. Getting HEAD SHA of main...");
  const ref = await ghApi(token, `/repos/${OWNER}/${REPO}/git/ref/heads/${BASE}`);
  const sha = ref.object.sha;
  console.log(`   HEAD sha: ${sha}`);

  // Check if branch already exists
  console.log(`2. Creating branch ${BRANCH}...`);
  try {
    await ghApi(token, `/repos/${OWNER}/${REPO}/git/refs`, "POST", {
      ref: `refs/heads/${BRANCH}`,
      sha,
    });
    console.log("   Branch created.");
  } catch (e) {
    if (e.message.includes("422")) {
      console.log("   Branch already exists, continuing.");
    } else {
      throw e;
    }
  }

  console.log(`3. Committing ${REPORT_PATH}...`);
  const contentB64 = Buffer.from(REPORT_CONTENT).toString("base64");

  // Check if file already exists on branch (to get its SHA for updates)
  let existingSha;
  try {
    const existing = await ghApi(
      token,
      `/repos/${OWNER}/${REPO}/contents/${REPORT_PATH}?ref=${encodeURIComponent(BRANCH)}`
    );
    existingSha = existing.sha;
    console.log("   File exists on branch, will update.");
  } catch {
    console.log("   File does not exist yet, will create.");
  }

  await ghApi(token, `/repos/${OWNER}/${REPO}/contents/${REPORT_PATH}`, "PUT", {
    message: `chore(reports): daily summary 2026-06-30 (token-keeper + ocr-sweep fixes)\n\nCo-Authored-By: Claude Sonnet 4.6 <noreply@anthropic.com>`,
    content: contentB64,
    branch: BRANCH,
    ...(existingSha ? { sha: existingSha } : {}),
  });
  console.log("   File committed.");

  console.log("4. Creating draft PR...");
  const pr = await ghApi(token, `/repos/${OWNER}/${REPO}/pulls`, "POST", {
    title: "chore(reports): daily summary 2026-06-30",
    head: BRANCH,
    base: BASE,
    draft: true,
    body: `## Daily Summary — 2026-06-30

One commit landed in the last 24 h: **PR #243** (\`333c922\`).

### token-keeper — QBO multi-entity rotation fixed
The QuickBooks OAuth provider was reading wrong placeholder secret names so every nightly rotation run silently no-op'd. Fixed secret names to the live \`qbo-*\` credentials and added a multi-tenant loop covering all 4 entities (otchealth, innd, hearingassist, personal). Dry-run verified.

### ocr-sweep — OOM guard added
A single large blob was OOM-killing the 1 Gi container, causing the \`docintel-ocr-sweep\` job to fail for 30+ hours with no text sidecars written. Added a \`MAX_MB=200\` guard that checks \`Content-Length\` before buffering, skipping oversize files. Job also bumped to 4 Gi / 2 CPU via ARM.

Full report: \`reports/daily-summary-2026-06-30.md\`

---
🤖 Generated with [Claude Code](https://claude.com/claude-code)`,
  });

  console.log(`\nDone! Draft PR created: ${pr.html_url}`);
  return pr.html_url;
}

main().catch((e) => {
  console.error("ERROR:", e.message);
  process.exit(1);
});
